Hãy tạo cho tôi một ứng dụng React sử dụng Vite, TypeScript và Material UI (MUI).
Ứng dụng này là một công cụ AI hỗ trợ viết Sáng kiến kinh nghiệm (SKKN).

Bước 1: Hãy tạo các file cấu hình và Type cơ bản.

1. Tạo file `src/types/index.ts` với nội dung sau:
```typescript
export type AppStatus =
  | "INITIALIZING"
  | "WAITING_FOR_API_KEY" // Có thể bỏ qua trạng thái này sau này
  | "SELECTING_LANGUAGE"
  | "GATHERING_INFO"
  | "GENERATING_OUTLINE"
  | "REVIEWING_OUTLINE"
  | "GENERATING_CONTENT"
  | "COMPLETED";

export type Language = "vi" | "en";
export type SectionStatus = "PENDING" | "GENERATING" | "COMPLETED";
export type WritingStyle = "heartfelt" | "factual" | "analytical" | "simple";

export interface UserInfo {
  name: string;
  school: string;
  phone: string;
  email: string;
  schoolYear: string;
}

export interface OutlineNode {
  id: string;
  title: string;
  targetWordCount: number;
  actualWordCount: number;
  content: string;
  status: SectionStatus;
  userGuidance: string;
  children?: OutlineNode[];
}

export interface SKKNTemplate {
  id: string;
  name: string;
  subject: string;
  description: string;
  outlineText: string;
}

export interface AppState {
  status: AppStatus;
  language: Language;
  apiKey: string | null;
  userInfo: UserInfo;
  topic: string;
  targetWordCount: number;
  customOutlineText: string;
  selectedTemplate: SKKNTemplate | null;
  outline: OutlineNode[];
  currentSectionId: string | null;
  progressIndex: number;
  errorMessage: string | null;
  writingStyle: WritingStyle;
}

export interface GeneratedSolution { title: string; }
export interface AIOutlineResponse { id: string; title: string; children?: AIOutlineResponse[]; }
export interface SKKNSuggestionInput { subject: string; gradeLevel: string; strength: string; product: string; goal: string; }
export interface SKKNSuggestion { id: string; title: string; description: string; }

