  ),
  Loader: () => (
    <svg className="animate-spin" xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="2" x2="12" y2="6"/><line x1="12" y1="18" x2="12" y2="22"/><line x1="4.93" y1="4.93" x2="7.76" y2="7.76"/><line x1="16.24" y1="16.24" x2="19.07" y2="19.07"/><line x1="2" y1="12" x2="6" y2="12"/><line x1="18" y1="12" x2="22" y2="12"/><line x1="4.93" y1="19.07" x2="7.76" y2="16.24"/><line x1="16.24" y1="7.76" x2="19.07" y2="4.93"/></svg>
  )
};

import { GoogleGenAI, Type } from "@google/genai";
import { SKKNSuggestionInput, SKKNSuggestion, AIOutlineResponse, OutlineNode, SectionStatus, WritingStyle } from "../types";

const MODEL_NAME = "gemini-3-flash-preview";

export class GeminiService {
  private ai: any;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  }

  async suggestTopics(input: SKKNSuggestionInput): Promise<SKKNSuggestion[]> {
    const prompt = `Bạn là một chuyên gia giáo dục tại Việt Nam. Dựa trên các thông tin sau, hãy gợi ý 3 tiêu đề Sáng kiến kinh nghiệm (SKKN) độc đáo, mang tính thực tiễn cao và đúng quy chuẩn giáo dục:
    - Môn học: ${input.subject}
    - Khối lớp: ${input.gradeLevel}
    - Thế mạnh giáo viên: ${input.strength}
    - Sản phẩm/Phương pháp áp dụng: ${input.product}
    - Mục tiêu đạt được: ${input.goal}

    Hãy trả về kết quả dưới dạng JSON là một mảng các đối tượng có 'title' (tiêu đề SKKN) và 'description' (mô tả ngắn gọn lý do chọn đề tài này).`;

    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["title", "description"]
          }
        }
      }
    });

    const results = JSON.parse(response.text || "[]");
    return results.map((r: any, idx: number) => ({ ...r, id: `topic-${idx}` }));
  }

  async generateOutline(topic: string, subject: string): Promise<OutlineNode[]> {
    const prompt = `Hãy xây dựng một khung đề cương chi tiết cho Sáng kiến kinh nghiệm với đề tài: "${topic}". 
    Đề cương phải tuân thủ cấu trúc chuẩn của Bộ Giáo dục Việt Nam:
    I. ĐẶT VẤN ĐỀ (Lý do chọn đề tài, Mục đích nghiên cứu, Đối tượng, Phạm vi...)
    II. GIẢI QUYẾT VẤN ĐỀ (Cơ sở lý luận, Thực trạng, Các giải pháp thực hiện, Hiệu quả...)
    III. KẾT LUẬN VÀ KIẾN NGHỊ

    Trả về cấu trúc JSON phân cấp. Mỗi mục có 'title' và mảng 'children'.`;

    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              children: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    title: { type: Type.STRING }
                  }
                }
              }
            },
            required: ["title"]
          }
        }
      }
    });

    const rawData = JSON.parse(response.text || "[]");

    const transform = (node: any): OutlineNode => ({
      id: Math.random().toString(36).substr(2, 9),
      title: node.title,
      targetWordCount: 400,
      actualWordCount: 0,
      content: "",
      status: "PENDING",
      userGuidance: "",
      children: node.children ? node.children.map(transform) : undefined
    });

    return rawData.map(transform);
  }

  async generateSectionContent(
    topic: string, 
    sectionTitle: string, 
    writingStyle: WritingStyle, 
    context: string
  ): Promise<string> {
    const styleDescription = {
      heartfelt: "tâm huyết, truyền cảm, chia sẻ trải nghiệm thực tế",
      factual: "thực tiễn, khách quan, dựa trên số liệu và kết quả cụ thể",
      analytical: "phân tích khoa học, logic, chặt chẽ, sử dụng thuật ngữ chuyên môn",
      simple: "đơn giản, dễ hiểu, súc tích"
    }[writingStyle];

    const prompt = `Viết nội dung cho phần "${sectionTitle}" của Sáng kiến kinh nghiệm đề tài: "${topic}".
    Yêu cầu:
    - Phong cách viết: ${styleDescription}.
    - Nội dung phải chuyên sâu, thực tế, đúng văn phong sư phạm Việt Nam.
    - Độ dài khoảng 300-500 từ.
    - Sử dụng các ví dụ minh họa nếu cần thiết.
    - Ngữ cảnh bổ sung: ${context || "Không có"}

    Chỉ trả về nội dung văn bản, không bao gồm tiêu đề hay các lời dẫn khác.`;

    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        temperature: 0.8,
      }
    });

    return response.text || "Không thể tạo nội dung cho phần này.";
  }
}

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { 
  AppState, 
  AppStatus, 
  UserInfo, 
  SKKNSuggestionInput, 
  SKKNSuggestion, 
  OutlineNode, 
  WritingStyle 
} from './types';
import { GeminiService } from './services/geminiService';
import { 
  SUBJECTS, 
  GRADE_LEVELS, 
  WRITING_STYLES, 
  ICONS, 
  APP_TITLE, 
  APP_SUBTITLE 
} from './constants';

const initialUserInfo: UserInfo = {
  name: "",
  school: "",
  phone: "",
  email: "",
  schoolYear: new Date().getFullYear().toString() + "-" + (new Date().getFullYear() + 1).toString()
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    status: "SELECTING_LANGUAGE",
    language: "vi",
    userInfo: initialUserInfo,
    topic: "",
    targetWordCount: 2000,
    customOutlineText: "",
    selectedTemplate: null,
    outline: [],
    currentSectionId: null,
    progressIndex: 0,
    errorMessage: null,
    writingStyle: "analytical"
  });

  const [isLoading, setIsLoading] = useState(false);
  const [topicSuggestions, setTopicSuggestions] = useState<SKKNSuggestion[]>([]);
  const gemini = useMemo(() => new GeminiService(), []);

  const updateStatus = (status: AppStatus) => setState(prev => ({ ...prev, status }));

  const handleInfoSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    updateStatus("GENERATING_TOPIC");
  };

  const handleTopicGeneration = async (input: SKKNSuggestionInput) => {
    setIsLoading(true);
    try {
      const suggestions = await gemini.suggestTopics(input);
      setTopicSuggestions(suggestions);
    } catch (err) {
      setState(prev => ({ ...prev, errorMessage: "Lỗi khi gợi ý đề tài. Vui lòng thử lại." }));
    } finally {
      setIsLoading(false);
    }
  };

  const selectTopic = async (topic: string) => {
    setState(prev => ({ ...prev, topic, status: "GENERATING_OUTLINE" }));
    setIsLoading(true);
    try {
      const outline = await gemini.generateOutline(topic, state.userInfo.school);
      setState(prev => ({ ...prev, outline, status: "REVIEWING_OUTLINE" }));
    } catch (err) {
      setState(prev => ({ ...prev, errorMessage: "Lỗi khi tạo đề cương." }));
    } finally {
      setIsLoading(false);
    }
  };

  const startWriting = () => {
    updateStatus("GENERATING_CONTENT");
  };

  const generateNextSection = async () => {
    const flattenNodes = (nodes: OutlineNode[]): OutlineNode[] => {
      let flat: OutlineNode[] = [];
      nodes.forEach(node => {
        flat.push(node);
        if (node.children) flat = [...flat, ...flattenNodes(node.children)];
      });
      return flat;
    };

    const flatOutline = flattenNodes(state.outline);
    const pendingNode = flatOutline.find(n => n.status === "PENDING");

    if (!pendingNode) {
      updateStatus("COMPLETED");
      return;
    }

    setIsLoading(true);
    try {
      const content = await gemini.generateSectionContent(
        state.topic, 
        pendingNode.title, 
        state.writingStyle,
        pendingNode.userGuidance
      );

      const updateNodeInOutline = (nodes: OutlineNode[]): OutlineNode[] => {
        return nodes.map(node => {
          if (node.id === pendingNode.id) {
            return { ...node, content, status: "COMPLETED", actualWordCount: content.split(" ").length };
          }
          if (node.children) {
            return { ...node, children: updateNodeInOutline(node.children) };
          }
          return node;
        });
      };

      setState(prev => ({
        ...prev,
        outline: updateNodeInOutline(prev.outline),
        progressIndex: prev.progressIndex + 1
      }));
    } catch (err) {
      setState(prev => ({ ...prev, errorMessage: "Lỗi khi viết nội dung phần " + pendingNode.title }));
    } finally {
      setIsLoading(false);
    }
  };

  const totalSections = useMemo(() => {
    const countNodes = (nodes: OutlineNode[]): number => {
      let count = nodes.length;
      nodes.forEach(n => { if (n.children) count += countNodes(n.children); });
      return count;
    };
    return countNodes(state.outline);
  }, [state.outline]);

  const progressPercent = Math.min(100, Math.round((state.progressIndex / totalSections) * 100));

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 text-white p-2 rounded-lg">
              <ICONS.Sparkles />
            </div>
            <h1 className="text-xl font-bold text-slate-800">{APP_TITLE}</h1>
          </div>
          <div className="text-xs text-slate-500 hidden sm:block">
            {APP_SUBTITLE}
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 pt-8">
        {state.errorMessage && (
          <div className="mb-6 p-4 bg-red-50 border border-red-100 text-red-700 rounded-xl flex items-center justify-between">
            <span>{state.errorMessage}</span>
            <button onClick={() => setState(p => ({ ...p, errorMessage: null }))} className="text-red-900 font-bold">&times;</button>
          </div>
        )}

        {/* Step: Selection */}
        {state.status === "SELECTING_LANGUAGE" && (
          <div className="text-center py-12">
            <h2 className="text-3xl font-extrabold text-slate-900 mb-4">Chào mừng đến với AI SKKN</h2>
            <p className="text-slate-600 mb-8">Công cụ hỗ trợ viết Sáng kiến kinh nghiệm chuyên nghiệp dành cho giáo viên.</p>
            <button 
              onClick={() => updateStatus("GATHERING_INFO")}
              className="bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-3 rounded-full font-semibold transition-all shadow-lg hover:shadow-indigo-200"
            >
              Bắt đầu ngay
            </button>
          </div>
        )}

        {/* Step: Info Gathering */}
        {state.status === "GATHERING_INFO" && (
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-2xl font-bold mb-6 flex items-center gap-2">
              <ICONS.Pen /> Thông tin người thực hiện
            </h2>
            <form onSubmit={handleInfoSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Họ và tên</label>
                <input 
                  required
                  type="text" 
                  value={state.userInfo.name}
                  onChange={(e) => setState(p => ({ ...p, userInfo: { ...p.userInfo, name: e.target.value } }))}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                  placeholder="Nguyễn Văn A"
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Đơn vị công tác</label>
                <input 
                  required
                  type="text" 
                  value={state.userInfo.school}
                  onChange={(e) => setState(p => ({ ...p, userInfo: { ...p.userInfo, school: e.target.value } }))}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                  placeholder="Trường THPT X"
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Năm học</label>
                <input 
                  type="text" 
                  value={state.userInfo.schoolYear}
                  onChange={(e) => setState(p => ({ ...p, userInfo: { ...p.userInfo, schoolYear: e.target.value } }))}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Số điện thoại</label>
                <input 
                  type="tel" 
                  value={state.userInfo.phone}
                  onChange={(e) => setState(p => ({ ...p, userInfo: { ...p.userInfo, phone: e.target.value } }))}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                />
              </div>
              <div className="md:col-span-2 pt-4">
                <button type="submit" className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition-colors flex items-center justify-center gap-2">
                  Tiếp tục <ICONS.ArrowRight />
                </button>
              </div>
            </form>
          </div>
        )}

        {/* Step: Topic Idea Selection */}
        {state.status === "GENERATING_TOPIC" && (
          <div className="space-y-8">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
              <h2 className="text-2xl font-bold mb-2">Tìm ý tưởng đề tài</h2>
              <p className="text-slate-500 mb-6 italic">Nhập các yếu tố thực tế tại lớp học của bạn để AI gợi ý đề tài phù hợp nhất.</p>

              <TopicForm onSubmit={handleTopicGeneration} isLoading={isLoading} />
            </div>

            {topicSuggestions.length > 0 && (
              <div className="space-y-4">
                <h3 className="text-lg font-semibold text-slate-700">Đề tài gợi ý dành cho bạn:</h3>
