                      <h4 className="font-bold text-slate-900 group-hover:text-indigo-600 transition-colors mb-2">{suggestion.title}</h4>
                      <p className="text-sm text-slate-500">{suggestion.description}</p>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* Step: Review Outline */}
        {state.status === "REVIEWING_OUTLINE" && (
          <div className="space-y-6">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
              <h2 className="text-2xl font-bold mb-4">Kiểm tra Đề cương</h2>
              <div className="p-4 bg-indigo-50 rounded-xl mb-6">
                <p className="text-sm text-indigo-700 font-medium">Đề tài: {state.topic}</p>
              </div>

              <div className="space-y-4 mb-8">
                {state.outline.map((node, i) => (
                  <OutlineItem key={node.id} node={node} index={i + 1} />
                ))}
              </div>

              <div className="border-t border-slate-100 pt-6 space-y-4">
                <h3 className="font-semibold">Chọn phong cách viết:</h3>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  {WRITING_STYLES.map((style) => (
                    <button
                      key={style.value}
                      onClick={() => setState(p => ({ ...p, writingStyle: style.value as WritingStyle }))}
                      className={`p-4 rounded-xl border text-left transition-all ${state.writingStyle === style.value ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-200 hover:border-indigo-300'}`}
                    >
                      <div className="font-bold text-sm mb-1">{style.label}</div>
                      <div className={`text-xs ${state.writingStyle === style.value ? 'text-indigo-100' : 'text-slate-500'}`}>{style.description}</div>
                    </button>
                  ))}
                </div>
                <button 
                  onClick={startWriting}
