              </div>
            </div>
          </div>
        )}

        {/* Step: Content Generation (Active Progress) */}
        {state.status === "GENERATING_CONTENT" && (
          <div className="space-y-6">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200 sticky top-20 z-10">
