                <div 
                  className="h-full bg-indigo-600 transition-all duration-500 ease-out" 
                  style={{ width: `${progressPercent}%` }}
                />
              </div>
              <div className="mt-4 flex justify-center">
                {state.progressIndex < totalSections ? (
                  <button 
                    disabled={isLoading}
                    onClick={generateNextSection}
                    className={`px-8 py-3 rounded-full font-bold transition-all flex items-center gap-2 ${isLoading ? 'bg-slate-200 text-slate-400' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-md'}`}
                  >
                    {isLoading ? <><ICONS.Loader /> Đang viết...</> : <>Tiếp tục phần tiếp theo <ICONS.ArrowRight /></>}
