                  <h1 className="uppercase font-bold text-2xl mb-10">Sáng kiến kinh nghiệm</h1>
                  <h2 className="text-xl font-bold mb-20">{state.topic}</h2>
                  <div className="text-left max-w-xs mx-auto space-y-2">
