                </div>

                {state.outline.map((node) => (
                  <div key={node.id} className="mb-10">
                    <h2 className="text-xl font-bold text-slate-900 border-b border-slate-200 pb-2 mb-4">{node.title}</h2>
                    <div className="whitespace-pre-wrap leading-relaxed text-slate-800">{node.content}</div>
