      {/* Floating Action Bar during generation */}
      {state.status === "GENERATING_CONTENT" && isLoading && (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-md px-6 py-3 rounded-full shadow-2xl border border-indigo-100 flex items-center gap-3 animate-bounce">
