import React, { createContext, useContext, useState, ReactNode } from 'react';
import { AppState, AppStatus, UserInfo, SKKNTemplate, OutlineNode, WritingStyle, Language } from '../types';

interface AppContextType {
  state: AppState;
  setTopic: (topic: string) => void;
  setTargetWordCount: (count: number) => void;
  setUserInfo: (info: UserInfo) => void;
  setCustomOutlineText: (text: string) => void;
  setSelectedTemplate: (template: SKKNTemplate | null) => void;
  setOutline: (outline: OutlineNode[]) => void;
  setStatus: (status: AppStatus) => void;
  setWritingStyle: (style: WritingStyle) => void;
  setLanguage: (lang: Language) => void;
  updateOutlineNode: (nodeId: string, updates: Partial<OutlineNode>) => void;
  setErrorMessage: (msg: string | null) => void;
  setProgressIndex: (index: number | ((prev: number) => number)) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AppState>({
    status: "GATHERING_INFO",
    language: "vi",
    userInfo: {
      name: "",
      school: "",
      phone: "",
      email: "",
      schoolYear: new Date().getFullYear().toString() + "-" + (new Date().getFullYear() + 1).toString()
    },
    topic: "",
    targetWordCount: 2000,
    customOutlineText: "",
    selectedTemplate: null,
    outline: [],
    currentSectionId: null,
    progressIndex: 0,
    errorMessage: null,
    writingStyle: "analytical"
  });

  const setTopic = (topic: string) => setState(s => ({ ...s, topic }));
  const setTargetWordCount = (targetWordCount: number) => setState(s => ({ ...s, targetWordCount }));
  const setUserInfo = (userInfo: UserInfo) => setState(s => ({ ...s, userInfo }));
  const setCustomOutlineText = (customOutlineText: string) => setState(s => ({ ...s, customOutlineText }));
  const setSelectedTemplate = (selectedTemplate: SKKNTemplate | null) => setState(s => ({ ...s, selectedTemplate }));
  const setOutline = (outline: OutlineNode[]) => setState(s => ({ ...s, outline }));
  const setStatus = (status: AppStatus) => setState(s => ({ ...s, status }));
  const setWritingStyle = (writingStyle: WritingStyle) => setState(s => ({ ...s, writingStyle }));
  const setLanguage = (language: Language) => setState(s => ({ ...s, language }));
  const setErrorMessage = (errorMessage: string | null) => setState(s => ({ ...s, errorMessage }));
  const setProgressIndex = (index: number | ((prev: number) => number)) => 
    setState(s => ({ ...s, progressIndex: typeof index === 'function' ? index(s.progressIndex) : index }));

  const updateOutlineNode = (nodeId: string, updates: Partial<OutlineNode>) => {
    const updateRecursive = (nodes: OutlineNode[]): OutlineNode[] => {
      return nodes.map(node => {
        if (node.id === nodeId) {
          return { ...node, ...updates };
        }
        if (node.children) {
          return { ...node, children: updateRecursive(node.children) };
        }
        return node;
      });
    };
    setState(s => ({ ...s, outline: updateRecursive(s.outline) }));
  };

  return (
    <AppContext.Provider value={{
      state,
      setTopic,
      setTargetWordCount,
      setUserInfo,
      setCustomOutlineText,
      setSelectedTemplate,
      setOutline,
      setStatus,
      setWritingStyle,
      setLanguage,
      updateOutlineNode,
      setErrorMessage,
      setProgressIndex
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useAppContext = () => {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error("useAppContext must be used within an AppProvider");
  }
  return context;
};

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { 
  AppStatus, 
  UserInfo, 
  SKKNSuggestionInput, 
  SKKNSuggestion, 
  OutlineNode, 
  WritingStyle 
} from './types';
import { GeminiService } from './services/geminiService';
import { 
  SUBJECTS, 
  GRADE_LEVELS, 
  WRITING_STYLES, 
  ICONS, 
  APP_TITLE, 
  APP_SUBTITLE 
} from './constants';
import { AppProvider, useAppContext } from './contexts/AppContext';

const SKKNApp: React.FC = () => {
  const { 
    state, 
    setStatus, 
    setTopic, 
    setOutline, 
    setUserInfo, 
    setWritingStyle, 
    updateOutlineNode, 
    setProgressIndex,
    setErrorMessage
  } = useAppContext();

  const [isLoading, setIsLoading] = useState(false);
  const [topicSuggestions, setTopicSuggestions] = useState<SKKNSuggestion[]>([]);
  const gemini = useMemo(() => new GeminiService(), []);

  const handleInfoSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setStatus("GENERATING_TOPIC");
  };

  const handleTopicGeneration = async (input: SKKNSuggestionInput) => {
    setIsLoading(true);
    setErrorMessage(null);
    try {
      const suggestions = await gemini.suggestTopics(input);
      setTopicSuggestions(suggestions);
    } catch (err) {
      setErrorMessage("Lỗi khi gợi ý đề tài. Vui lòng thử lại.");
    } finally {
      setIsLoading(false);
    }
  };

  const selectTopic = async (topic: string) => {
    setTopic(topic);
    setStatus("GENERATING_OUTLINE");
    setIsLoading(true);
    setErrorMessage(null);
    try {
      const outline = await gemini.generateOutline(topic, state.userInfo.school);
      setOutline(outline);
      setStatus("REVIEWING_OUTLINE");
    } catch (err) {
      setErrorMessage("Lỗi khi tạo đề cương.");
      setStatus("GENERATING_TOPIC");
    } finally {
      setIsLoading(false);
    }
  };

  const startWriting = () => {
    setStatus("GENERATING_CONTENT");
  };

  const generateNextSection = async () => {
    const flattenNodes = (nodes: OutlineNode[]): OutlineNode[] => {
      let flat: OutlineNode[] = [];
      nodes.forEach(node => {
        flat.push(node);
        if (node.children) flat = [...flat, ...flattenNodes(node.children)];
      });
      return flat;
    };

    const flatOutline = flattenNodes(state.outline);
    const pendingNode = flatOutline.find(n => n.status === "PENDING");

    if (!pendingNode) {
      setStatus("COMPLETED");
      return;
    }

    setIsLoading(true);
    setErrorMessage(null);
    try {
      const content = await gemini.generateSectionContent(
        state.topic, 
        pendingNode.title, 
        state.writingStyle,
        pendingNode.userGuidance
      );

      updateOutlineNode(pendingNode.id, {
        content,
        status: "COMPLETED",
        actualWordCount: content.split(/\s+/).filter(Boolean).length
      });

      setProgressIndex(prev => prev + 1);
    } catch (err) {
      setErrorMessage("Lỗi khi viết nội dung phần " + pendingNode.title);
    } finally {
      setIsLoading(false);
    }
  };

  const totalSections = useMemo(() => {
    const countNodes = (nodes: OutlineNode[]): number => {
      let count = nodes.length;
      nodes.forEach(n => { if (n.children) count += countNodes(n.children); });
      return count;
    };
    return countNodes(state.outline);
  }, [state.outline]);

  const progressPercent = totalSections > 0 ? Math.min(100, Math.round((state.progressIndex / totalSections) * 100)) : 0;

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-20">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 text-white p-2 rounded-lg">
              <ICONS.Sparkles />
            </div>
            <h1 className="text-xl font-bold text-slate-800">{APP_TITLE}</h1>
          </div>
          <div className="text-xs text-slate-500 hidden sm:block">
            {APP_SUBTITLE}
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 pt-8">
        {state.errorMessage && (
          <div className="mb-6 p-4 bg-red-50 border border-red-100 text-red-700 rounded-xl flex items-center justify-between">
            <span>{state.errorMessage}</span>
            <button onClick={() => setErrorMessage(null)} className="text-red-900 font-bold">&times;</button>
          </div>
        )}

        {state.status === "GATHERING_INFO" && (
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200 animate-in fade-in zoom-in-95">
            <h2 className="text-2xl font-bold mb-6 flex items-center gap-2">
              <ICONS.Pen /> Thông tin người thực hiện
            </h2>
            <form onSubmit={handleInfoSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Họ và tên</label>
                <input 
                  required
                  type="text" 
                  value={state.userInfo.name}
                  onChange={(e) => setUserInfo({ ...state.userInfo, name: e.target.value })}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                  placeholder="Nguyễn Văn A"
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Đơn vị công tác</label>
                <input 
                  required
                  type="text" 
                  value={state.userInfo.school}
                  onChange={(e) => setUserInfo({ ...state.userInfo, school: e.target.value })}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                  placeholder="Trường THPT X"
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700">Năm học</label>
                <input 
                  type="text" 
