                {state.progressIndex < totalSections ? (
                  <button 
                    disabled={isLoading}
                    onClick={generateNextSection}
                    className={`px-8 py-3 rounded-full font-bold transition-all flex items-center gap-2 ${isLoading ? 'bg-slate-200 text-slate-400' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-md'}`}
                  >
                    {isLoading ? <><ICONS.Loader /> Đang viết...</> : <>Viết phần tiếp theo <ICONS.ArrowRight /></>}
                  </button>
                ) : (
                  <button 
                    onClick={() => setStatus("COMPLETED")}
                    className="px-8 py-3 bg-green-600 text-white rounded-full font-bold hover:bg-green-700 shadow-md"
                  >
                    Xem kết quả cuối cùng
                  </button>
