              </div>
            </div>

            <div className="space-y-6 pb-20">
               {state.outline.map((node) => (
                 <CompletedSection key={node.id} node={node} />
               ))}
            </div>
          </div>
        )}

        {state.status === "COMPLETED" && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
              <div className="flex items-center justify-between mb-8">
                <div>
                  <h2 className="text-3xl font-extrabold text-slate-900">Hoàn tất!</h2>
                  <p className="text-slate-500">Sáng kiến kinh nghiệm của bạn đã sẵn sàng.</p>
                </div>
                <button 
                  onClick={() => window.print()}
                  className="p-3 bg-slate-100 hover:bg-slate-200 rounded-full transition-all"
