                  <h2 className="text-xl font-bold mb-20 px-10 italic">"{state.topic}"</h2>
                  <div className="text-left max-w-xs mx-auto space-y-2 border-t pt-6 border-slate-200">
                    <p><strong>Người thực hiện:</strong> {state.userInfo.name}</p>
                    <p><strong>Đơn vị:</strong> {state.userInfo.school}</p>
                    <p><strong>Năm học:</strong> {state.userInfo.schoolYear}</p>
                  </div>
                </div>

                {state.outline.map((node) => (
                  <div key={node.id} className="mb-10 page-break-inside-avoid">
                    <h2 className="text-xl font-bold text-slate-900 border-b border-slate-200 pb-2 mb-4">{node.title}</h2>
                    <div className="whitespace-pre-wrap leading-relaxed text-slate-800 text-justify">{node.content}</div>
                    {node.children?.map(child => (
                      <div key={child.id} className="mt-6 pl-4 border-l-2 border-slate-50">
                        <h3 className="text-lg font-bold text-slate-800 mb-3">{child.title}</h3>
                        <div className="whitespace-pre-wrap leading-relaxed text-slate-700 text-justify">{child.content}</div>
                      </div>
                    ))}
