        </div>
        <h3 className="font-bold text-lg text-slate-900">{node.title}</h3>
      </div>
      <div className="text-slate-700 whitespace-pre-wrap leading-relaxed text-sm italic border-l-2 border-indigo-100 pl-4 bg-slate-50/50 p-3 rounded-r-lg">
        {node.content || "Đang soạn thảo..."}
      </div>

      {node.children && node.children.some(c => c.status === "COMPLETED") && (
        <div className="mt-6 space-y-6">
          {node.children.map(child => (
            child.status === "COMPLETED" && (
              <div key={child.id} className="pl-6 border-l-2 border-slate-100">
                <h4 className="font-bold text-slate-800 mb-2 text-md">{child.title}</h4>
                <p className="text-sm text-slate-600 whitespace-pre-wrap">{child.content}</p>
              </div>
            )
          ))}
        </div>
      )}
    </div>
  );
};

