} from "../constants/prompts";

const MODEL_NAME = "gemini-3-flash-preview";

// Helper for retry logic
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

async function retryWithBackoff<T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    if (retries > 0 && error?.status === 429) {
      await sleep(delay);
      return retryWithBackoff(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

export class AIService {
  private getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  }

  async generateSkknSuggestions(input: SKKNSuggestionInput): Promise<SKKNSuggestion[]> {
    const ai = this.getAI();
    return retryWithBackoff(async () => {
      const response = await ai.models.generateContent({
        model: MODEL_NAME,
        contents: SUGGEST_TOPICS_PROMPT(input),
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                description: { type: Type.STRING }
              },
              required: ["title", "description"]
            }
          }
        }
      });

      const data = JSON.parse(response.text || "[]");
      return data.map((item: any, idx: number) => ({
        id: `suggest-${idx}-${Date.now()}`,
        title: item.title,
        description: item.description
      }));
    });
  }

  async parseCustomOutline(text: string): Promise<OutlineNode[]> {
    const ai = this.getAI();
    return retryWithBackoff(async () => {
      const response = await ai.models.generateContent({
        model: MODEL_NAME,
        contents: PARSE_OUTLINE_PROMPT(text),
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                children: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      id: { type: Type.STRING },
                      title: { type: Type.STRING }
                    }
                  }
                }
              },
              required: ["id", "title"]
            }
          }
        }
      });

      const data = JSON.parse(response.text || "[]");

      const transform = (item: any): OutlineNode => ({
        id: item.id || Math.random().toString(36).substr(2, 9),
        title: item.title,
        targetWordCount: 500,
        actualWordCount: 0,
        content: "",
        status: "PENDING",
        userGuidance: "",
        children: item.children ? item.children.map(transform) : undefined
      });

      return data.map(transform);
    });
  }

  async generateSectionContent(
    topic: string, 
    sectionTitle: string, 
    writingStyle: WritingStyle, 
    context: string
  ): Promise<string> {
    const ai = this.getAI();
    const stylePrompt = WRITING_STYLE_PROMPTS[writingStyle];

    return retryWithBackoff(async () => {
      const response = await ai.models.generateContent({
        model: MODEL_NAME,
        contents: GENERATE_SECTION_PROMPT(topic, sectionTitle, stylePrompt, context),
        config: {
          temperature: 0.7,
        }
      });

      return response.text || "";
    });
  }
}

