const SKKNApp: React.FC = () => {
  const { 
    state, 
    setStatus, 
    setTopic, 
    setOutline, 
    setUserInfo, 
    setWritingStyle, 
    updateOutlineNode, 
    setProgressIndex,
    setErrorMessage
  } = useAppContext();

  const [isLoading, setIsLoading] = useState(false);
  const [topicSuggestions, setTopicSuggestions] = useState<SKKNSuggestion[]>([]);

  const handleInfoSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setStatus("GENERATING_TOPIC");
  };

  const handleTopicGeneration = async (input: SKKNSuggestionInput) => {
    setIsLoading(true);
    setErrorMessage(null);
    try {
      const suggestions = await aiService.generateSkknSuggestions(input);
      setTopicSuggestions(suggestions);
    } catch (err: any) {
      console.error(err);
      setErrorMessage("Lỗi khi gợi ý đề tài. Vui lòng thử lại sau.");
    } finally {
      setIsLoading(false);
    }
  };

  const selectTopic = async (topic: string) => {
    setTopic(topic);
    setStatus("GENERATING_OUTLINE");
    setIsLoading(true);
    setErrorMessage(null);
    try {
      // Find if this topic matches any template to get its outline text, otherwise default
      const template = SKKN_TEMPLATES.find(t => t.name === topic);
      const outlineText = template ? template.outlineText : "I. Đặt vấn đề\nII. Giải quyết vấn đề\nIII. Kết luận";

      const outline = await aiService.parseCustomOutline(outlineText);
      setOutline(outline);
      setStatus("REVIEWING_OUTLINE");
    } catch (err: any) {
      console.error(err);
      setErrorMessage("Lỗi khi tạo đề cương.");
      setStatus("GENERATING_TOPIC");
    } finally {
      setIsLoading(false);
    }
  };

  const startWriting = () => {
    setStatus("GENERATING_CONTENT");
  };

  const generateNextSection = async () => {
    const flattenNodes = (nodes: OutlineNode[]): OutlineNode[] => {
      let flat: OutlineNode[] = [];
      nodes.forEach(node => {
        flat.push(node);
        if (node.children) flat = [...flat, ...flattenNodes(node.children)];
      });
      return flat;
    };

    const flatOutline = flattenNodes(state.outline);
    const pendingNode = flatOutline.find(n => n.status === "PENDING");

    if (!pendingNode) {
      setStatus("COMPLETED");
      return;
    }

    setIsLoading(true);
    setErrorMessage(null);
    try {
      const content = await aiService.generateSectionContent(
        state.topic, 
        pendingNode.title, 
        state.writingStyle,
        pendingNode.userGuidance
      );

      updateOutlineNode(pendingNode.id, {
        content,
        status: "COMPLETED",
        actualWordCount: content.split(/\s+/).filter(Boolean).length
      });

      setProgressIndex(prev => prev + 1);
    } catch (err: any) {
      console.error(err);
      setErrorMessage("Lỗi khi viết nội dung phần " + pendingNode.title);
    } finally {
      setIsLoading(false);
    }
  };

  const totalSections = useMemo(() => {
    const countNodes = (nodes: OutlineNode[]): number => {
      let count = nodes.length;
      nodes.forEach(n => { if (n.children) count += countNodes(n.children); });
      return count;
    };
    return countNodes(state.outline);
  }, [state.outline]);

