import { OutlineNode } from '../types';

export const formatTitle = (index: number, level: number): string => {
  const roman = ['I', 'II', 'III', 'IV', 'V', 'VI', 'VII', 'VIII', 'IX', 'X'];
  if (level === 0) return roman[index] || (index + 1).toString();
  return `${index + 1}.`;
};

export const getAllLeafNodes = (nodes: OutlineNode[]): OutlineNode[] => {
  let leaves: OutlineNode[] = [];
  nodes.forEach(node => {
    if (!node.children || node.children.length === 0) {
      leaves.push(node);
    } else {
      leaves = [...leaves, ...getAllLeafNodes(node.children)];
    }
  });
  return leaves;
};

export const flattenOutline = (nodes: OutlineNode[]): OutlineNode[] => {
  let flat: OutlineNode[] = [];
  nodes.forEach(node => {
    flat.push(node);
    if (node.children) {
      flat = [...flat, ...flattenOutline(node.children)];
    }
  });
  return flat;
};

export const countWords = (text: string): number => {
  if (!text) return 0;
  return text.trim().split(/\s+/).filter(Boolean).length;
};

export const copyToClipboard = async (text: string): Promise<boolean> => {
  try {
    await navigator.clipboard.writeText(text);
    return true;
  } catch (err) {
    console.error('Failed to copy: ', err);
    return false;
  }
};

export const exportToWord = (content: string, filename: string) => {
  console.log('Exporting to Word...', filename);
  // Basic implementation using a blob for mock export
  const header = "<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><title>SKKN</title></head><body>";
  const footer = "</body></html>";
  const sourceHTML = header + content.replace(/\n/g, '<br>') + footer;

  const blob = new Blob(['\ufeff', sourceHTML], {
    type: 'application/msword'
  });

  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = filename + '.doc';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

