import { SKKNSuggestionInput, SKKNSuggestion } from './types';
import { aiService } from './services/aiService';
import { exportToWord } from './utils/exportService';

const SKKNApp: React.FC = () => {
  const { 
    state, 
    setStatus, 
    setTopic, 
    setOutline, 
    setErrorMessage
  } = useAppContext();

  const [isLoadingTopics, setIsLoadingTopics] = React.useState(false);
