        {state.status === "REVIEWING_OUTLINE" && <OutlineReviewScreen />}

        {state.status === "GENERATING_CONTENT" && <WorkspaceScreen />}

        {state.status === "COMPLETED" && (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4">
             <div className="bg-white p-12 rounded-3xl shadow-xl border border-slate-200">
               <div className="text-center mb-16 border-b-2 border-slate-100 pb-12">
                 <h1 className="text-sm font-bold text-indigo-600 uppercase tracking-[0.2em] mb-4">Hoàn tất Sáng kiến kinh nghiệm</h1>
                 <h2 className="text-3xl font-extrabold text-slate-900 px-10 italic">"{state.topic}"</h2>
                 <div className="mt-8 flex justify-center gap-8 text-sm text-slate-500 font-medium">
                   <span>Tác giả: {state.userInfo.name}</span>
                   <span>Đơn vị: {state.userInfo.school}</span>
                 </div>
               </div>

               <div className="prose prose-slate max-w-none">
                 {state.outline.map((node) => (
                   <div key={node.id} className="mb-12">
                     <h3 className="text-xl font-bold text-slate-900 mb-6 border-l-4 border-indigo-600 pl-4">{node.title}</h3>
                     <div className="text-slate-700 leading-relaxed text-justify whitespace-pre-wrap">{node.content}</div>
                     {node.children?.map(child => (
                        <div key={child.id} className="mt-8 ml-8">
                          <h4 className="text-lg font-bold text-slate-800 mb-4">{child.title}</h4>
                          <div className="text-slate-600 leading-relaxed text-justify whitespace-pre-wrap">{child.content}</div>
                        </div>
                     ))}
                   </div>
                 ))}
               </div>
             </div>

             <div className="flex justify-center">
               <button onClick={() => window.location.reload()} className="text-indigo-600 font-bold hover:underline">Viết bài mới</button>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

const App: React.FC = () => (
  <AppProvider>
    <SKKNApp />
  </AppProvider>
