            <div className="p-10 flex-grow overflow-auto prose prose-slate max-w-none bg-[url('https://www.transparenttextures.com/patterns/pinstripe-light.png')] bg-fixed">
              {isWriting && selectedNode.id === currentWritingNode?.id ? (
