          // 4. Ưu tiên 4: Nếu không khớp gì cả, yêu cầu AI khởi tạo dàn ý từ text mặc định
          // Hoặc có thể yêu cầu AI tự tạo dàn ý hoàn toàn mới từ Topic (chưa triển khai sâu)
          const defaultText = "I. Đặt vấn đề\n1. Lý do chọn đề tài\nII. Giải quyết vấn đề\n1. Thực trạng\n2. Giải pháp\nIII. Kết luận";
          outline = await aiService.parseCustomOutline(defaultText);
        }
      }

      setOutline(outline);
      setStatus("REVIEWING_OUTLINE");
    } catch (err) {
      setErrorMessage("Không thể tạo dàn ý. Vui lòng thử lại.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDetailedChange = (field: string, value: string) => {
    setDetailedConfig({ [field]: value });
  };

  const handleSelectTemplate = (template: SKKNTemplate) => {
    setTopic(template.name);
    setSelectedTemplate(template);
    setSubject(template.subject);
  };

  return (
