import React, { useState, useEffect, useCallback } from 'react';
import { useAppContext } from '../contexts/AppContext';
import { ICONS, EDUCATION_LEVELS, SUBJECTS } from '../constants';
import { aiService } from '../services/aiService';
import { SKKNSuggestion } from '../types';

export const TopicSuggestionScreen: React.FC = () => {
  const { state, setTopic, setStatus, setEducationLevel, setSubject } = useAppContext();
  const [formData, setFormData] = useState({
    strength: "",
    product: "",
    goal: ""
  });
  const [isGenerating, setIsGenerating] = useState(false);
  const [suggestions, setSuggestions] = useState<SKKNSuggestion[]>([]);

  const handleGenerate = useCallback(async (isAuto = false) => {
    // Nếu là tự động và đã có gợi ý, không tự chạy lại trừ khi đổi môn/cấp
    setIsGenerating(true);
    try {
      const results = await aiService.generateSkknSuggestions({
        educationLevel: state.educationLevel,
        subject: state.subject,
        strength: formData.strength,
        product: formData.product,
        goal: formData.goal
      });
      setSuggestions(results);
    } catch (error) {
      console.error("Failed to suggest topics", error);
    } finally {
      setIsGenerating(false);
    }
  }, [state.educationLevel, state.subject, formData]);

  // Tự động gợi ý khi vào màn hình hoặc đổi môn học/cấp học
  useEffect(() => {
    const timer = setTimeout(() => {
      handleGenerate(true);
    }, 500); // Debounce nhẹ để tránh gọi API quá dồn dập khi click nhanh
    return () => clearTimeout(timer);
  }, [state.educationLevel, state.subject]);

  const selectTopic = (title: string) => {
    setTopic(title);
    setStatus("GATHERING_INFO");
  };

  const onFormSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleGenerate();
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <div className="flex items-center gap-4">
        <button 
          onClick={() => setStatus("GATHERING_INFO")}
          className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-500 hover:text-indigo-600 transition-all shadow-sm"
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="19" y1="12" x2="5" y2="12"/><polyline points="12 19 5 12 12 5"/></svg>
        </button>
        <div>
          <h2 className="text-3xl font-extrabold text-slate-900">Tư vấn đề tài SKKN</h2>
          <p className="text-slate-500">AI sẽ tự động gợi ý đề tài dựa trên Môn học. Nhập thêm thông tin để có kết quả chính xác hơn.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Form Input */}
        <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-200 h-fit space-y-6">
           <form onSubmit={onFormSubmit} className="space-y-5">
             <div className="grid grid-cols-2 gap-4">
               <div className="space-y-2">
                 <label className="text-sm font-bold text-slate-700">Cấp học</label>
                 <select 
                    value={state.educationLevel}
                    onChange={(e) => setEducationLevel(e.target.value)}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500"
                 >
                   {EDUCATION_LEVELS.map(l => <option key={l} value={l}>{l}</option>)}
                 </select>
               </div>
               <div className="space-y-2">
                 <label className="text-sm font-bold text-slate-700">Môn học</label>
                 <select 
                    value={state.subject}
                    onChange={(e) => setSubject(e.target.value)}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500"
                 >
                   {SUBJECTS.map(s => <option key={s} value={s}>{s}</option>)}
                 </select>
               </div>
             </div>

             <div className="space-y-2">
               <label className="text-sm font-bold text-slate-700">Thế mạnh của bạn? (Không bắt buộc)</label>
               <textarea 
                value={formData.strength}
                onChange={(e) => setFormData({...formData, strength: e.target.value})}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 min-h-[80px]"
                placeholder="VD: CNTT, tâm lý học sinh..."
               />
             </div>

             <div className="space-y-2">
               <label className="text-sm font-bold text-slate-700">Công cụ/Phương pháp muốn áp dụng? (Tùy chọn)</label>
               <textarea 
                value={formData.product}
                onChange={(e) => setFormData({...formData, product: e.target.value})}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 min-h-[80px]"
                placeholder="VD: Quizizz, STEM, Sơ đồ tư duy..."
               />
             </div>

             <div className="space-y-2">
               <label className="text-sm font-bold text-slate-700">Mục tiêu? (Tùy chọn)</label>
               <textarea 
                value={formData.goal}
                onChange={(e) => setFormData({...formData, goal: e.target.value})}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 min-h-[80px]"
                placeholder="VD: Tăng hứng thú, phát triển năng lực nói..."
               />
             </div>

             <button 
              disabled={isGenerating}
              type="submit"
              className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-bold text-lg hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all flex items-center justify-center gap-2"
             >
               {isGenerating ? <><ICONS.Loader /> Đang phân tích...</> : <><ICONS.Sparkles /> Tinh chỉnh theo thông tin trên</>}
             </button>
           </form>
        </div>

        {/* Suggestions Column */}
        <div className="space-y-6">
           {isGenerating ? (
             <div className="h-full flex flex-col items-center justify-center space-y-4 p-20 bg-white rounded-3xl border-2 border-dashed border-slate-200">
               <div className="relative">
                 <div className="absolute inset-0 bg-indigo-100 rounded-full blur-xl animate-pulse"></div>
                 <div className="relative text-indigo-600 animate-spin">
                    <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v4"/><path d="m16.2 7.8 2.9-2.9"/><path d="M18 12h4"/><path d="m16.2 16.2 2.9 2.9"/><path d="M12 18v4"/><path d="m4.9 19.1 2.9-2.9"/><path d="M2 12h4"/><path d="m4.9 4.9 2.9 2.9"/></svg>
                 </div>
               </div>
               <p className="text-slate-500 font-bold italic animate-pulse">AI đang tìm các đề tài hay cho môn {state.subject}...</p>
             </div>
           ) : suggestions.length > 0 ? (
             <div className="space-y-4 animate-in fade-in slide-in-from-right-4">
               <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2 px-2">
                 <span className="p-1.5 bg-green-100 text-green-600 rounded-lg"><ICONS.Check /></span>
                 Gợi ý đề tài môn {state.subject}
               </h3>
               {suggestions.map((s, idx) => (
                 <div key={s.id} className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm hover:shadow-md transition-all group border-l-4 border-l-transparent hover:border-l-indigo-600">
                   <div className="flex justify-between items-start gap-4">
                      <div className="flex-grow">
                        <h4 className="font-bold text-slate-900 text-lg group-hover:text-indigo-600 transition-colors leading-snug">
                          {s.title}
                        </h4>
                        <p className="text-sm text-slate-500 mt-2 leading-relaxed italic">
                          {s.description}
                        </p>
                      </div>
                      <button 
                        onClick={() => selectTopic(s.title)}
                        className="p-3 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-600 hover:text-white transition-all flex-shrink-0 shadow-sm"
                        title="Sử dụng đề tài này"
                      >
                        <ICONS.ArrowRight />
                      </button>
                   </div>
                 </div>
               ))}
               <div className="p-4 bg-amber-50 rounded-2xl border border-amber-100 text-amber-800 text-xs flex items-start gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="flex-shrink-0 mt-0.5"><circle cx="12" cy="12" r="10"/><line x1="12" y1="16" x2="12" y2="12"/><line x1="12" y1="8" x2="12.01" y2="8"/></svg>
                 <span>Mẹo: Hãy nhập thêm "Thế mạnh" hoặc "Công cụ" ở bên trái để AI đưa ra các đề tài sát với thực tế giảng dạy của bạn hơn.</span>
               </div>
             </div>
           ) : (
             <div className="h-full flex flex-col items-center justify-center p-20 bg-slate-50/50 rounded-3xl border border-dashed border-slate-200 text-slate-400">
               <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mb-4 shadow-sm">
                 <ICONS.Sparkles />
               </div>
               <p className="text-center font-medium max-w-[240px]">Đang chuẩn bị các gợi ý đề tài...</p>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

